from typing import Protocol
class EntityStore(Protocol):
    def get(self, id: str): ...
    def save(self, entity) -> None: ...
class InMemoryStore:
    def __init__(self):
        self._d = {}
    def get(self, id: str):
        return self._d.get(id)
    def save(self, entity) -> None:
        self._d[entity['id']] = entity
s = InMemoryStore(); s.save({'id': 'C1'})
print(s.get('C1'))

